# Prompt: Using Python: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    # Define discount percentages based on user role
    discounts = {
        "enterprise": 0.3,
        "premium": 0.15,
        "basic": 0
    }

    # Calculate the total price of items in cart
    total_price = sum(item["price"] * item["quantity"] for item in cart_items)

    # Apply discount to cart total if applicable
    if user.role in discounts:
        discounted_price = total_price - (total_price * discounts[user.role])
    else:
        print("Invalid user role")
        return None

    # Process payment with discounted price
    payment_details["amount"] = discounted_price
    payment_status = process_payment_with_discounts(payment_details)

    return payment_status


def process_payment_with_discounts(payment_details):
    # Simulate processing payment (you may want to replace this function)
    print("Processing payment...")
    if "amount" in payment_details:
        print(f"Payment successful. Amount: {payment_details['amount']}")
        return True
    else:
        print("Failed to process payment")
        return False


